#include <stdio.h>
#include <stdlib.h>
int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, max = -1, count = 0;
        int arr[51];
        for (int i = 0; i < 51; i++) arr[i] = 0;
        for (int i = 0; i <= 50; i++) {
            int temp;
            scanf("%d", &temp);
            if (count == 0) N = temp;
            else arr[count - 1] = temp;
            count++;
            if (count > N) break;
        }
        qsort(arr, N, sizeof(int), compare);
        printf("%d\n", arr[N - 1]);
    }
    return 0;
}

