const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    let N = null;
    let arr = [];
    let nums = readline().split(' ').map(x => parseInt(x));
    for (let num of nums) {
        if (N === null) {
            N = num;
        } else {
            arr.push(num);
        }
        if (arr.length === N) break;
    }
    arr.sort((a, b) => a - b);
    console.log(arr[arr.length - 1]);
}

